const results = $input.item.json.organic_results || [];
const top5 = results.slice(0, 5).map(r => ({
  title: r.title,
  description: r.snippet,
  url: r.link
}));

const serp_text = top5.map((r, i) => 
  `Result ${i+1}:\nTitle: ${r.title}\nDescription: ${r.description}\nURL: ${r.url}`
).join('\n\n');

const analysis_prompt = `Analyse these top 5 Google SERP results for the keyword "${$input.item.json.search_parameters.q}":

${serp_text}

Extract and return ONLY valid JSON:
{
  "common_words": "most repeated words/phrases across titles and descriptions",
  "avg_title_length": "average character count of titles",
  "avg_desc_length": "average character count of descriptions",
  "ctas_used": "specific CTAs found e.g. Book Online, Call Now, Get a Free Quote",
  "value_props": "specific value propositions e.g. $0 call out fee, same day service, 5 star rated, 500+ reviews",
  "emotional_triggers": "emotional/trust words e.g. trusted, certified, licensed, guaranteed, award-winning",
  "title_patterns": "exact title structures e.g. Keyword + Location | Value Prop, Best Keyword + Year | Brand",
  "location_signals": "location specific words used e.g. Sydney, Melbourne, local, near me",
  "trust_signals": "trust indicators e.g. years in business, number of reviews, certifications, guarantees",
  "price_signals": "any pricing mentions e.g. free quotes, $0 call out, upfront pricing, no hidden fees"
}`;

return {
  json: {
    keyword: $input.item.json.search_parameters.q,
    region: $input.item.json.search_parameters.gl,
    serp_results: top5,
    serp_text: serp_text,
    serp_analysis_body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 500,
      messages: [{ role: "user", content: analysis_prompt }]
    })
  }
};

const keyword = $('Get row(s) in sheet').item.json["Target Keyword"];
const serp_text = $('Code in JavaScript').item.json.serp_text;

// Get SERP analysis from Claude
const serp_analysis_raw = $('HTTP Request3').item.json.content[0].text;
let serp_analysis;
try {
  const cleaned_analysis = serp_analysis_raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  serp_analysis = JSON.parse(cleaned_analysis);
} catch(e) {
  serp_analysis = { common_words: '', ctas_used: '', value_props: '', emotional_triggers: '', title_patterns: '', location_signals: '', trust_signals: '', price_signals: '' };
}

// Get page context from Claude
const page_context_raw = $('HTTP Request4').item.json.content[0].text;
let page_context;
try {
  const cleaned_context = page_context_raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  page_context = JSON.parse(cleaned_context);
} catch(e) {
  page_context = { main_topic: '', search_intent: 'transactional', page_type: 'service page', target_audience: '' };
}

// Page content logic — using sheet data now
const page_url = $('Get row(s) in sheet').item.json["Mapped URL"];
const jina_content = $('HTTP Request').item.json.data || '';
const jina_failed = !jina_content || jina_content.length < 100;
const page_content = jina_failed ? '' : jina_content;
const content_source = jina_failed ? 'Jina failed - using SERP only' : 'Auto-fetched from: ' + page_url;

// Auto extract USPs from page content
const usp_prompt_section = page_content ? 
  `PAGE CONTENT (use this to extract unique selling points of this specific business):
${page_content.substring(0, 3000)}` : 
  'No page content available';

// Get existing meta titles to prevent duplication
const existing_titles = $('Get row(s) in sheet').all()
  .map(row => row.json["Meta Title"])
  .filter(title => title && title.trim() !== '');

const existing_titles_text = existing_titles.length > 0 ? 
  `EXISTING META TITLES ALREADY IN USE (do NOT generate these or anything similar):
${existing_titles.map((t, i) => `${i+1}. ${t}`).join('\n')}` : '';

const prompt = `You are an expert SEO copywriter specialising in high-converting meta tags.
Generate an SEO Meta Title and Meta Description for the following page.

KEYWORD: ${keyword}

PAGE CONTEXT:
- Main topic: ${page_context.main_topic}
- Search intent: ${page_context.search_intent}
- Page type: ${page_context.page_type}
- Target audience: ${page_context.target_audience}

SERP INTELLIGENCE (from top ranking pages in target region):
- Common words/phrases: ${serp_analysis.common_words}
- CTAs being used: ${serp_analysis.ctas_used}
- Value propositions: ${serp_analysis.value_props}
- Emotional triggers: ${serp_analysis.emotional_triggers}
- Common title patterns: ${serp_analysis.title_patterns}
- Location signals: ${serp_analysis.location_signals}
- Trust signals: ${serp_analysis.trust_signals}
- Price signals: ${serp_analysis.price_signals}

TOP SERP RESULTS FOR REFERENCE:
${serp_text}

${usp_prompt_section}

${existing_titles_text}

INSTRUCTIONS:
- If page content is available, use specific details from it to make the meta unique
- If page content is NOT available, use SERP intelligence alone to write the best possible meta
- NEVER ask for more information — ALWAYS return JSON regardless

STRICT RULES:
- Meta Title: STRICT 50-60 characters. Must include keyword "${keyword}" near the start. No generic phrases.
- Meta Description: STRICT 140-155 characters. Must include keyword "${keyword}". Use specific USPs. End with a CTA.
- BOTH title AND description MUST contain the exact keyword "${keyword}"
- Do NOT use generic phrases like: "professional services", "high quality", "best in class", "we are here to help"
- Do NOT copy competitor titles or descriptions
- Every word must earn its place — be specific, be compelling
- NEVER explain yourself — ALWAYS return JSON no matter what

Return ONLY valid JSON, no explanation, no preamble, nothing else:
{"meta_title": "...", "meta_description": "..."}`;

return {
  json: {
    keyword: keyword,
    content_source: content_source,
    serp_analysis: serp_analysis,
    page_context: page_context,
    prompt: prompt,
    api_body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 1000,
      messages: [{ role: "user", content: prompt }]
    })
  }
};

const attempt = $input.item.json.attempt || 1;
const content = $input.item.json.content[0].text;
const jsonMatch = content.match(/\{[\s\S]*\}/);
if (!jsonMatch) throw new Error('No JSON found in Claude response: ' + content);
const cleaned = jsonMatch[0].trim();
const parsed = JSON.parse(cleaned);

const keyword = $('Get row(s) in sheet').item.json["Target Keyword"].toLowerCase();
const meta_title = parsed.meta_title;
const meta_description = parsed.meta_description;

const keyword_words = keyword.split(' ').filter(w => w.length > 3);
const keyword_in_title = meta_title.toLowerCase().includes(keyword) || 
  keyword_words.every(w => meta_title.toLowerCase().includes(w));
const keyword_in_desc = meta_description.toLowerCase().includes(keyword) || 
  keyword_words.every(w => meta_description.toLowerCase().includes(w));

// CTR optimisation check
const power_words = ['best', 'top', 'free', 'now', 'today', 'trusted', 'expert', 'certified', 'guaranteed', 'fast', 'same day', 'emergency', '24/7', 'local', 'award'];
const has_power_word = power_words.some(w => meta_title.toLowerCase().includes(w) || meta_description.toLowerCase().includes(w));
const has_number = /\d/.test(meta_title);
const has_cta = /call|book|get|shop|find|discover|try|start|contact|enquire|visit|learn|explore|request|schedule|order|buy|check|see|compare|download|sign up|apply|join/i.test(meta_description);

// Duplication check against other rows in sheet
const all_rows = $('Get row(s) in sheet').all();
const duplicate_title = all_rows.some(row => 
  row.json["Meta Title"] && 
  row.json["Meta Title"].toLowerCase() === meta_title.toLowerCase() &&
  row.json["row_number"] !== $('Get row(s) in sheet').item.json["row_number"]
);

let status;
let issues = [];

if (!keyword_in_title) issues.push('Keyword missing from title');
if (!keyword_in_desc) issues.push('Keyword missing from description');
if (meta_title.length < 40) issues.push(`Title too short (${meta_title.length} chars)`);
if (meta_title.length > 63) issues.push(`Title too long (${meta_title.length} chars)`);
if (meta_description.length < 130) issues.push(`Description too short (${meta_description.length} chars)`);
if (meta_description.length > 165) issues.push(`Description too long (${meta_description.length} chars)`);
if (!has_cta) issues.push('No CTA in description');
if (duplicate_title) issues.push('Duplicate title detected');

// CTR score
let ctr_score = 0;
if (keyword_in_title) ctr_score += 30;
if (has_power_word) ctr_score += 25;
if (has_number) ctr_score += 20;
if (has_cta) ctr_score += 25;

if (issues.length === 0) {
  status = '✅ Pass';
} else {
  status = '⚠️ ' + issues.join(' | ');
}

return {
  json: {
    attempt: attempt,
    row_number: $('Get row(s) in sheet').item.json["row_number"],
    meta_title: meta_title,
    meta_description: meta_description,
    title_length: meta_title.length,
    desc_length: meta_description.length,
    keyword_in_title: keyword_in_title,
    keyword_in_desc: keyword_in_desc,
    status: status,
    api_body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 1000,
      messages: [{ role: "user", content: $('Code in JavaScript1').first().json.prompt }]
    })
  }
};

const page_url = $('Get row(s) in sheet').item.json["Mapped URL"];
const jina_content = $('HTTP Request').item.json.data || '';
const keyword = $('Get row(s) in sheet').item.json["Target Keyword"];
const page_content = jina_content ? jina_content.substring(0, 2000) : 'No content available';

const context_body = JSON.stringify({
  model: "claude-sonnet-4-20250514",
  max_tokens: 300,
  messages: [{
    role: "user",
    content: `Analyse this page content for the keyword "${keyword}" and return ONLY valid JSON:
{
  "main_topic": "what this page is mainly about in one sentence",
  "search_intent": "informational or transactional or navigational or commercial",
  "page_type": "homepage or service page or product page or blog or category page",
  "target_audience": "who this page is targeting"
}

PAGE CONTENT:
${page_content}

Return ONLY valid JSON, nothing else.`
  }]
});

return {
  json: {
    context_body: context_body
  }
};

return {
  json: {
    attempt: $input.item.json.attempt + 1,
    api_body: $input.item.json.api_body,
    content: [{ text: $input.item.json.api_body }]
  }
};

const rows = $input.all();

const filtered = rows.filter(row => {
  const keyword = row.json["Target Keyword"];
  const metaTitle = row.json["Meta Title"];
  return keyword && keyword.trim() !== '' && (!metaTitle || metaTitle.trim() === '');
});

return filtered;
